const checkpoints = [];

const tyres = JSON.parse(localStorage.getItem('tyre_products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Qualifying tyres by size, season, and price
const candidates = tyres.filter(t => t && t.is_available !== false &&
  t.width === 205 && t.profile === 55 && t.rim_diameter === 16 &&
  t.season === 'winter' &&
  typeof t.price_per_tyre === 'number' && t.price_per_tyre <= 120
);

// Determine highest customer rating among candidates
let bestRating = null;
for (const t of candidates) {
  const r = typeof t.customer_rating === 'number' ? t.customer_rating : 0;
  if (bestRating === null || r > bestRating) bestRating = r;
}

const bestTyreIds = candidates
  .filter(t => {
    const r = typeof t.customer_rating === 'number' ? t.customer_rating : 0;
    return bestRating !== null && r === bestRating;
  })
  .map(t => t.id);

// Cart items for those highest-rated qualifying tyres
const bestCartItems = cartItems.filter(ci => bestTyreIds.includes(ci.tyre_product_id));
const totalQtyBest = bestCartItems.reduce((sum, ci) => sum + (ci.quantity || 0), 0);

// CP1 (0.5): User added at least one tyre that meets all filters and is among the highest-rated options
checkpoints.push({
  passed: bestCartItems.length > 0,
  weight: 0.5
});

// CP2 (0.5): Total quantity of these highest-rated tyres is at least 4
checkpoints.push({
  passed: totalQtyBest >= 4,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('service_bookings') || '[]');
const timeSlots = JSON.parse(localStorage.getItem('time_slots') || '[]');
const branches = JSON.parse(localStorage.getItem('branches') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

// Compute 15th of next month based on baselineDate
let targetDateStr = null;
if (metadata && metadata.baselineDate) {
  const now = new Date(metadata.baselineDate);
  const year = now.getUTCFullYear();
  const month = now.getUTCMonth(); // 0-11
  const nextMonth = (month + 1) % 12;
  const targetYear = year + (month === 11 ? 1 : 0);
  const targetDate = new Date(Date.UTC(targetYear, nextMonth, 15));
  targetDateStr = targetDate.toISOString().split('T')[0];
}

// Nearest branches to ZIP 10001 that support in-center wheel alignment
const searchZip = '10001';
const alignmentBranches = branches
  .filter(b => b && b.is_active !== false &&
    (b.type === 'service_center' || b.type === 'combined_center') &&
    b.has_wheel_alignment === true)
  .map(b => ({
    branch: b,
    distance_miles: b.zip_code === searchZip ? 0 : 50
  }));

alignmentBranches.sort((a, b) => a.distance_miles - b.distance_miles);
const minDistance = alignmentBranches.length ? alignmentBranches[0].distance_miles : null;
const nearestBranchIds = alignmentBranches
  .filter(x => x.distance_miles === minDistance)
  .map(x => x.branch.id);

// Candidate bookings: wheel alignment at nearest branch(es), in-center
const candidateBookings = bookings.filter(b =>
  b && b.service_code === 'wheel_alignment' &&
  b.mode === 'in_center' &&
  nearestBranchIds.includes(b.branch_id)
);

// CP1 (0.4): Booked wheel alignment at the nearest suitable branch to ZIP 10001
checkpoints.push({
  passed: candidateBookings.length > 0,
  weight: 0.4
});

// Bookings on 15th of next month between 10:00 and 12:00
const bookingsCorrectDateTime = candidateBookings.filter(b => {
  const slot = timeSlots.find(ts => ts.id === b.time_slot_id);
  if (!slot) return false;
  const slotDateStr = (typeof slot.slot_date === 'string'
    ? slot.slot_date.split('T')[0]
    : new Date(slot.slot_date).toISOString().split('T')[0]);
  if (targetDateStr && slotDateStr !== targetDateStr) return false;
  if (!slot.start_time || !slot.end_time) return false;
  if (slot.start_time < '10:00' || slot.start_time > '12:00') return false;
  if (slot.end_time < '10:00' || slot.end_time > '12:00') return false;
  return true;
});

// CP2 (0.3): Chosen slot is on the 15th of next month within 10:00–12:00
checkpoints.push({
  passed: bookingsCorrectDateTime.length > 0,
  weight: 0.3
});

// CP3 (0.3): Among all wheel alignment slots on that date within 10:00–12:00, the earliest start time was chosen
let earliestSlotId = null;
if (targetDateStr) {
  const candidateSlots = timeSlots.filter(ts => {
    if (!ts) return false;
    if (ts.slot_type !== 'service_booking') return false;
    if (ts.service_id !== 'wheel_alignment') return false;
    const slotDateStr = (typeof ts.slot_date === 'string'
      ? ts.slot_date.split('T')[0]
      : new Date(ts.slot_date).toISOString().split('T')[0]);
    if (slotDateStr !== targetDateStr) return false;
    if (!ts.start_time) return false;
    if (ts.start_time < '10:00' || ts.start_time > '12:00') return false;
    return true;
  });
  candidateSlots.sort((a, b) => {
    if (a.start_time < b.start_time) return -1;
    if (a.start_time > b.start_time) return 1;
    return 0;
  });
  if (candidateSlots.length) {
    earliestSlotId = candidateSlots[0].id;
  }
}

const usedEarliest = bookingsCorrectDateTime.some(b => b.time_slot_id === earliestSlotId);

checkpoints.push({
  passed: !!earliestSlotId && usedEarliest,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const tyres = JSON.parse(localStorage.getItem('tyre_products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Qualifying tyres by size, season, brand tier, free fitting, and price
const candidates = tyres.filter(t => t && t.is_available !== false &&
  t.width === 225 && t.profile === 45 && t.rim_diameter === 17 &&
  t.season === 'all_season' &&
  t.brand_tier === 'mid_range' &&
  t.has_free_fitting === true &&
  typeof t.price_per_tyre === 'number' && t.price_per_tyre <= 150
);

// Find cheapest among candidates
let minPrice = null;
for (const t of candidates) {
  const p = typeof t.price_per_tyre === 'number' ? t.price_per_tyre : Infinity;
  if (minPrice === null || p < minPrice) minPrice = p;
}

const cheapestIds = candidates
  .filter(t => minPrice !== null && typeof t.price_per_tyre === 'number' && t.price_per_tyre === minPrice)
  .map(t => t.id);

const cheapestCartItems = cartItems.filter(ci => cheapestIds.includes(ci.tyre_product_id));
const totalQty = cheapestCartItems.reduce((sum, ci) => sum + (ci.quantity || 0), 0);

// CP1 (0.6): User added at least one tyre that is the cheapest qualifying option
checkpoints.push({
  passed: cheapestCartItems.length > 0,
  weight: 0.6
});

// CP2 (0.4): Total quantity of that cheapest qualifying tyre is at least 2
checkpoints.push({
  passed: totalQty >= 2,
  weight: 0.4
});

return checkoints = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('service_bookings') || '[]');
const timeSlots = JSON.parse(localStorage.getItem('time_slots') || '[]');
const branches = JSON.parse(localStorage.getItem('branches') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

// Compute 14-day window from baselineDate
let startDate = null;
let endDate = null;
if (metadata && metadata.baselineDate) {
  startDate = new Date(metadata.baselineDate);
  const endMs = startDate.getTime() + 14 * 24 * 60 * 60 * 1000;
  endDate = new Date(endMs);
}

function isWithinWindow(slotDate) {
  if (!startDate || !endDate || !slotDate) return false;
  const d = new Date(slotDate);
  return d >= startDate && d <= endDate;
}

// Nearest branches to 94105 that offer full service in-center
const searchZip = '94105';
const fullBranches = branches
  .filter(b => b && b.is_active !== false &&
    (b.type === 'service_center' || b.type === 'combined_center') &&
    b.has_full_service === true)
  .map(b => ({
    branch: b,
    distance_miles: b.zip_code === searchZip ? 0 : 50
  }));

fullBranches.sort((a, b) => a.distance_miles - b.distance_miles);
const minDistance = fullBranches.length ? fullBranches[0].distance_miles : null;
const nearestBranchIds = fullBranches
  .filter(x => x.distance_miles === minDistance)
  .map(x => x.branch.id);

// Candidate bookings: full_service at nearest branch, in-center, correct vehicle details
const candidateBookings = bookings.filter(b =>
  b && b.service_code === 'full_service' &&
  b.mode === 'in_center' &&
  nearestBranchIds.includes(b.branch_id) &&
  (b.vehicle_make || '').toLowerCase() === 'toyota' &&
  (b.vehicle_model || '').toLowerCase() === 'corolla' &&
  b.vehicle_year === 2018 &&
  (b.fuel_type || '').toLowerCase() === 'petrol'
);

// CP1 (0.4): Correct service, branch, and vehicle details
checkpoints.push({
  passed: candidateBookings.length > 0,
  weight: 0.4
});

// Candidate bookings in next 14 days with 09:00–11:00 slot
const bookingsCorrectWindow = candidateBookings.filter(b => {
  const slot = timeSlots.find(ts => ts.id === b.time_slot_id);
  if (!slot) return false;
  if (!isWithinWindow(slot.slot_date)) return false;
  if (slot.slot_type !== 'service_booking') return false;
  if (!slot.start_time || !slot.end_time) return false;
  if (slot.start_time < '09:00' || slot.start_time > '11:00') return false;
  if (slot.end_time < '09:00' || slot.end_time > '11:00') return false;
  return true;
});

// CP2 (0.3): Booking is within the 14-day window and in a 09:00–11:00 slot
checkpoints.push({
  passed: bookingsCorrectWindow.length > 0,
  weight: 0.3
});

// CP3 (0.3): Chosen slot is the earliest matching 09:00–11:00 full service slot at nearest branch in that window
let earliestSlotId = null;
if (startDate && endDate) {
  const candidateSlots = timeSlots.filter(ts => {
    if (!ts) return false;
    if (ts.slot_type !== 'service_booking') return false;
    if (ts.service_id !== 'full_service') return false;
    if (!nearestBranchIds.includes(ts.branch_id)) return false;
    if (!ts.start_time || !ts.end_time) return false;
    if (ts.start_time < '09:00' || ts.start_time > '11:00') return false;
    if (ts.end_time < '09:00' || ts.end_time > '11:00') return false;
    if (!isWithinWindow(ts.slot_date)) return false;
    return true;
  }).sort((a, b) => {
    const da = new Date(a.slot_date).getTime();
    const db = new Date(b.slot_date).getTime();
    if (da !== db) return da - db;
    if (a.start_time < b.start_time) return -1;
    if (a.start_time > b.start_time) return 1;
    return 0;
  });
  if (candidateSlots.length) {
    earliestSlotId = candidateSlots[0].id;
  }
}

const usedEarliest = bookingsCorrectWindow.some(b => b.time_slot_id === earliestSlotId);

checkpoints.push({
  passed: !!earliestSlotId && usedEarliest,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const tyres = JSON.parse(localStorage.getItem('tyre_products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const speedOrder = ['q', 'r', 's', 't', 'h', 'v', 'w', 'y', 'zr'];
const minIndex = speedOrder.indexOf('w');

// Qualifying tyres by size, season, performance category, price, and speed rating ≥ W
const candidates = tyres.filter(t => {
  if (!t || t.is_available === false) return false;
  if (t.width !== 195 || t.profile !== 50 || t.rim_diameter !== 15) return false;
  if (t.season !== 'summer') return false;
  if (!(t.performance_category === 'performance' || t.performance_category === 'sport')) return false;
  if (typeof t.price_per_tyre !== 'number' || t.price_per_tyre > 150) return false;
  const idx = speedOrder.indexOf(t.speed_rating);
  if (minIndex !== -1 && (idx === -1 || idx < minIndex)) return false;
  // Customer rating ≥ 4.5 cannot be reliably checked from current static data, so it's not enforced here
  return true;
});

// Find cheapest among candidates
let minPrice = null;
for (const t of candidates) {
  const p = typeof t.price_per_tyre === 'number' ? t.price_per_tyre : Infinity;
  if (minPrice === null || p < minPrice) minPrice = p;
}

const cheapestIds = candidates
  .filter(t => minPrice !== null && typeof t.price_per_tyre === 'number' && t.price_per_tyre === minPrice)
  .map(t => t.id);

const cheapestCartItems = cartItems.filter(ci => cheapestIds.includes(ci.tyre_product_id));
const totalQty = cheapestCartItems.reduce((sum, ci) => sum + (ci.quantity || 0), 0);

// CP1 (0.6): User added at least one tyre that is the cheapest qualifying performance/sport summer 195/50 R15 option
checkpoints.push({
  passed: cheapestCartItems.length > 0,
  weight: 0.6
});

// CP2 (0.4): Total quantity of that cheapest qualifying tyre is at least 2
checkpoints.push({
  passed: totalQty >= 2,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('service_bookings') || '[]');
const timeSlots = JSON.parse(localStorage.getItem('time_slots') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

// Compute next Friday from baselineDate
let targetDateStr = null;
if (metadata && metadata.baselineDate) {
  const base = new Date(metadata.baselineDate);
  const day = base.getUTCDay(); // 0-6
  const friday = 5;
  let delta = (friday - day + 7) % 7;
  if (delta === 0) delta = 7; // ensure 'next' Friday is in the future
  const target = new Date(base.getTime() + delta * 24 * 60 * 60 * 1000);
  targetDateStr = target.toISOString().split('T')[0];
}

// Mobile oil change bookings at home address in ZIP 30301
const mobileBookings = bookings.filter(b =>
  b && b.service_code === 'oil_change' &&
  b.mode === 'mobile' &&
  (((b.mobile_zip_code || '') === '30301') || ((b.zip_code || '') === '30301')) &&
  (b.mobile_address_line1 || '').trim().length > 0 &&
  (b.mobile_city || '').toLowerCase() === 'atlanta'
);

// CP1 (0.4): Correct mobile oil change booking to a home address in ZIP 30301
checkpoints.push({
  passed: mobileBookings.length > 0,
  weight: 0.4
});

// Among these, find bookings on next Friday with start time before 11:00
const bookingsCorrectDateTime = mobileBookings.filter(b => {
  const slot = timeSlots.find(ts => ts.id === b.time_slot_id);
  if (!slot) return false;
  const slotDateStr = (typeof slot.slot_date === 'string'
    ? slot.slot_date.split('T')[0]
    : new Date(slot.slot_date).toISOString().split('T')[0]);
  if (targetDateStr && slotDateStr !== targetDateStr) return false;
  if (!slot.start_time) return false;
  if (slot.start_time >= '11:00') return false;
  return true;
});

// CP2 (0.3): Booking is on next Friday in a morning slot starting before 11:00
checkpoints.push({
  passed: bookingsCorrectDateTime.length > 0,
  weight: 0.3
});

// CP3 (0.3): Promo code SAVE20 applied with a positive discount and booking confirmed
const withPromoAndConfirmed = bookingsCorrectDateTime.filter(b =>
  (b.promo_code || '').toUpperCase() === 'SAVE20' &&
  typeof b.promo_discount_amount === 'number' && b.promo_discount_amount > 0 &&
  b.status === 'confirmed'
);

checkpoints.push({
  passed: withPromoAndConfirmed.length > 0,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const tyres = JSON.parse(localStorage.getItem('tyre_products') || '[]');
const comparisonSets = JSON.parse(localStorage.getItem('tyre_comparison_sets') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const tyreById = {};
for (const t of tyres) {
  if (t && t.id) tyreById[t.id] = t;
}

// Base filter: 225/40 R18 summer tyres under or equal to $140
function meetsBaseFilter(t) {
  if (!t || t.is_available === false) return false;
  if (t.width !== 225 || t.profile !== 40 || t.rim_diameter !== 18) return false;
  if (t.season !== 'summer') return false;
  if (typeof t.price_per_tyre !== 'number' || t.price_per_tyre > 140) return false;
  return true;
}

// Comparison sets where all tyres meet the base filter (and at least 2 tyres compared)
const correctComparisonSets = comparisonSets.filter(set => {
  if (!set || !Array.isArray(set.tyre_product_ids)) return false;
  if (set.tyre_product_ids.length < 2) return false;
  const tyresInSet = set.tyre_product_ids.map(id => tyreById[id]).filter(Boolean);
  if (tyresInSet.length !== set.tyre_product_ids.length) return false;
  return tyresInSet.every(meetsBaseFilter);
});

// CP1 (0.4): User created at least one comparison set with the correct 225/40 R18 summer under-$140 filter
checkpoints.push({
  passed: correctComparisonSets.length > 0,
  weight: 0.4
});

// Full filter: base filter + noise ≤70 dB + fuel efficiency A or B
function meetsFullFilter(t) {
  if (!meetsBaseFilter(t)) return false;
  if (typeof t.noise_db !== 'number' || t.noise_db > 70) return false;
  const fuel = (t.fuel_efficiency_rating || '').toLowerCase();
  if (fuel !== 'a' && fuel !== 'b') return false;
  return true;
}

// Tyres that meet the full filter AND appear in at least one correct comparison set
const comparisonTyreIds = new Set();
for (const set of correctComparisonSets) {
  for (const id of (set.tyre_product_ids || [])) {
    comparisonTyreIds.add(id);
  }
}

const eligibleTyreIds = tyres
  .filter(t => meetsFullFilter(t) && comparisonTyreIds.has(t.id))
  .map(t => t.id);

let hasEligibleWith4 = false;
for (const id of eligibleTyreIds) {
  const qty = cartItems
    .filter(ci => ci.tyre_product_id === id)
    .reduce((sum, ci) => sum + (ci.quantity || 0), 0);
  if (qty >= 4) {
    hasEligibleWith4 = true;
    break;
  }
}

// CP2 (0.6): User added 4 tyres from a compared option that meets noise and fuel-efficiency constraints
checkpoints.push({
  passed: hasEligibleWith4,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const fittings = JSON.parse(localStorage.getItem('fitting_appointments') || '[]');
const timeSlots = JSON.parse(localStorage.getItem('time_slots') || '[]');
const branches = JSON.parse(localStorage.getItem('branches') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

// Determine second Saturday-open tyre-fitting location near ZIP 60601
const searchZip = '60601';
const candidateBranches = branches
  .filter(b => b && b.is_active !== false && b.open_on_saturday === true && b.has_tyre_fitting === true)
  .map(b => ({
    branch: b,
    distance_miles: b.zip_code === searchZip ? 0 : 50
  }));

candidateBranches.sort((a, b) => a.distance_miles - b.distance_miles);
const secondBranch = candidateBranches.length >= 2 ? candidateBranches[1].branch : null;
const secondBranchId = secondBranch ? secondBranch.id : null;

// Fitting appointments at that branch linked to at least one existing cart item
let apptsAtSecond = [];
if (secondBranchId) {
  apptsAtSecond = fittings.filter(fa =>
    fa && fa.branch_id === secondBranchId &&
    Array.isArray(fa.cart_item_ids) &&
    fa.cart_item_ids.some(id => cartItems.some(ci => ci.id === id))
  );
}

// CP1 (0.4): Fitting appointment booked at the second Saturday-open tyre-fitting location for tyres in the cart
checkpoints.push({
  passed: apptsAtSecond.length > 0,
  weight: 0.4
});

// Compute next Saturday from baselineDate
let saturdayDateStr = null;
if (metadata && metadata.baselineDate) {
  const base = new Date(metadata.baselineDate);
  const day = base.getUTCDay(); // 0-6
  const saturday = 6;
  let delta = (saturday - day + 7) % 7;
  if (delta === 0) delta = 7; // ensure 'next' Saturday
  const target = new Date(base.getTime() + delta * 24 * 60 * 60 * 1000);
  saturdayDateStr = target.toISOString().split('T')[0];
}

// Appointments that use a Saturday 13:00–15:00 fitting slot
const apptsCorrectTime = apptsAtSecond.filter(fa => {
  const slot = timeSlots.find(ts => ts.id === fa.time_slot_id && ts.slot_type === 'fitting_appointment');
  if (!slot) return false;
  const slotDateStr = (typeof slot.slot_date === 'string'
    ? slot.slot_date.split('T')[0]
    : new Date(slot.slot_date).toISOString().split('T')[0]);
  const slotDateObj = new Date(slot.slot_date);
  const dow = slotDateObj.getUTCDay();
  if (dow !== 6) return false; // must be Saturday
  if (!slot.start_time || !slot.end_time) return false;
  if (slot.start_time < '13:00' || slot.start_time > '15:00') return false;
  if (slot.end_time < '13:00' || slot.end_time > '15:00') return false;
  return true;
});

// CP2 (0.3): Appointment is on a Saturday between 13:00 and 15:00
checkpoints.push({
  passed: apptsCorrectTime.length > 0,
  weight: 0.3
});

// Appointments specifically on the next available Saturday
const apptsCorrectDate = apptsCorrectTime.filter(fa => {
  const slot = timeSlots.find(ts => ts.id === fa.time_slot_id);
  if (!slot) return false;
  const slotDateStr = (typeof slot.slot_date === 'string'
    ? slot.slot_date.split('T')[0]
    : new Date(slot.slot_date).toISOString().split('T')[0]);
  return saturdayDateStr && slotDateStr === saturdayDateStr;
});

// CP3 (0.3): Saturday selected is the next Saturday from the baseline date
checkpoints.push({
  passed: apptsCorrectDate.length > 0,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
